1	export type Cell = [number, number];
2	
3	const SURVIVAL_NEIGHBORS = 2;
4	const BIRTH_NEIGHBORS = 3;
5	
6	const cellKey = (x: number, y: number): string => `${x},${y}`;
7	
8	const parseKey = (k: string): Cell => {
9	  const [xs, ys] = k.split(",");
10	  return [Number(xs), Number(ys)];
11	};
12	
13	const neighborOffsets: ReadonlyArray<Cell> = [
14	  [-1, -1], [-1, 0], [-1, 1],
15	  [0, -1],           [0, 1],
16	  [1, -1],  [1, 0],  [1, 1],
17	];
18	
19	function countNeighbors(cells: Cell[]): Map<string, number> {
20	  const counts = new Map<string, number>();
21	  for (const [x, y] of cells) {
22	    for (const [dx, dy] of neighborOffsets) {
23	      const k = cellKey(x + dx, y + dy);
24	      counts.set(k, (counts.get(k) ?? 0) + 1);
25	    }
26	  }
27	  return counts;
28	}
29	
30	function survives(neighborCount: number, isAlive: boolean): boolean {
31	  if (neighborCount === BIRTH_NEIGHBORS) return true;
32	  return neighborCount === SURVIVAL_NEIGHBORS && isAlive;
33	}
34	
35	export function nextGeneration(cells: Cell[]): Cell[] {
36	  const alive = new Set(cells.map(([x, y]) => cellKey(x, y)));
37	  const neighborCounts = countNeighbors(cells);
38	  const result: Cell[] = [];
39	  for (const [k, count] of neighborCounts) {
40	    if (survives(count, alive.has(k))) {
41	      result.push(parseKey(k));
42	    }
43	  }
44	  return result;
45	}
